export interface Transaction {
  id: string;
  amount: number;
  method: 'UPI_QR' | 'UPI_ID' | 'CARD' | 'INSTANT_APP';
  status: 'SUCCESS' | 'FAILED' | 'PENDING';
  timestamp: number;
  details: string;
  note?: string;
  recipientUpi?: string; // UPI ID or dynamic VPA
  payerUpi?: string;
  error?: string;
  errorCode?: string;
  verificationSecure?: boolean;
  metadata?: {
    device?: string;
    deviceFriendly?: string;
    location?: string;
    userActions?: string[];
    attempts?: number;
    failureReason?: string;
    userEmail?: string;
    userName?: string;
  };
  recipientType?: 'MOBILE' | 'UPI' | 'ACCOUNT';
  recipientName?: string;
  recipientMobile?: string;
  recipientAccount?: string;
  recipientIfsc?: string;
  recipientBankName?: string;
  senderUid?: string;
  senderEmail?: string;
  senderName?: string;
  recipientUid?: string | null;
  bankAccountId?: string; // Links transaction to local bank account debit source
  tags?: string[];
  currency?: 'INR' | 'USD' | 'EUR' | 'GBP';
}

export interface BankAccount {
  id: string;
  bankName: string;
  accountNo: string;
  ifscCode: string;
  accountHolderName: string;
  balance: number;
  pin: string;
  upiId?: string;
  mobileNo?: string;
  isPrimary?: boolean;
  status?: 'PENDING' | 'ACTIVE' | 'REJECTED';
}

export interface UserLoginLog {
  id: string;
  name: string;
  upi: string;
  address: string;
  timestamp: number;
  dateString: string;
  timeString: string;
  status: 'SUCCESS' | 'FAILED';
  ip: string;
  device: string;
}

export interface SupportTicket {
  id: string;
  userName: string;
  userUpi: string;
  subject: string;
  message: string;
  status: 'OPEN' | 'RESOLVED';
  createdAt: number;
  reply?: string;
}

